   194→/**
   195→ * Get knowledge silos - projects with only one developer
   196→ */
   197→export async function getKnowledgeSilos(
   198→	orgId: string,
   199→	params: { days?: number; min_sessions?: number } = {},
   200→): Promise<KnowledgeSilo[]> {
   201→	const { days = 30, min_sessions = 5 } = params;
   202→	const org = escapeString(orgId);
   203→	const d = Number(days);
   204→	const minSess = Number(min_sessions);
   205→
   206→	const query = `
   207→    SELECT
   208→      project_path,
   209→      any(user_id) as sole_user,
   210→      COUNT(*) as sessions,
   211→      CASE
   212→        WHEN COUNT(*) >= 20 THEN 'high'
   213→        WHEN COUNT(*) >= 10 THEN 'medium'
   214→        ELSE 'low'
   215→      END as risk_level
   216→    FROM rudel.session_analytics
   217→    WHERE ${buildDateFilter(d)}
   218→      AND organization_id = '${org}'
   219→      AND project_path != ''
   220→    GROUP BY project_path
   221→    HAVING COUNT(DISTINCT user_id) = 1
   222→      AND COUNT(*) >= ${minSess}
   223→    ORDER BY sessions DESC
   224→  `;
   225→
   226→	const results = await queryClickhouse<KnowledgeSilo>(query);
   227→
   228→	return results.map((silo) => ({
   229→		...silo,
   230→		project_name: extractProjectName(silo.project_path),
   231→		repository_name: extractRepositoryName(silo.project_path),
   232→	}));
   233→}
