   235→/**
   236→ * Get project activity trend over time
   237→ */
   238→export async function getProjectActivity(
   239→	orgId: string,
   240→	projectPath: string,
   241→	params: { days?: number; granularity?: "day" | "week" | "month" } = {},
   242→): Promise<ProjectActivity[]> {
   243→	const { days = 30, granularity = "day" } = params;
   244→	const org = escapeString(orgId);
   245→	const pp = escapeString(projectPath);
   246→	const d = Number(days);
   247→
   248→	let dateGrouping = "toDate(session_date)";
   249→	if (granularity === "week") {
   250→		dateGrouping = "toMonday(session_date)";
   251→	} else if (granularity === "month") {
   252→		dateGrouping = "toStartOfMonth(session_date)";
   253→	}
   254→
   255→	const query = `
   256→    WITH project_key AS (
   257→      SELECT if(git_remote != '', git_remote, if(package_name != '', package_name, project_path)) as pk, any(project_path) as project_path
   258→      FROM rudel.session_analytics
   259→      WHERE project_path = '${pp}'
   260→        AND (git_remote != '' OR package_name != '' OR project_path != '')
   261→        AND organization_id = '${org}'
   262→      LIMIT 1
   263→    )
   264→    SELECT
   265→      toString(${dateGrouping}) as date,
   266→      pk.project_path,
   267→      COUNT(*) as sessions,
   268→      COUNT(DISTINCT s.user_id) as unique_users
   269→    FROM project_key pk
   270→    INNER JOIN rudel.session_analytics s ON if(s.git_remote != '', s.git_remote, if(s.package_name != '', s.package_name, s.project_path)) = pk.pk
   271→    WHERE s.${buildDateFilter(d)}
   272→      AND s.organization_id = '${org}'
   273→    GROUP BY ${dateGrouping}, pk.project_path
   274→    ORDER BY date ASC
   275→  `;
   276→
   277→	return queryClickhouse<ProjectActivity>(query);
   278→}
   279→
   280→/**
   281→ * Get project summary statistics
   282→ */
   283→export async function getProjectSummary(
   284→	orgId: string,
   285→	days = 30,
   286→): Promise<ProjectSummary> {
   287→	const org = escapeString(orgId);
   288→	const d = Number(days);
   289→
   290→	const query = `
   291→    WITH project_stats AS (
   292→      SELECT
   293→        project_path,
   294→        COUNT(*) as sessions,
   295→        COUNT(DISTINCT user_id) as users
   296→      FROM rudel.session_analytics
   297→      WHERE ${buildDateFilter(d)}
   298→        AND organization_id = '${org}'
   299→        AND project_path != ''
   300→      GROUP BY project_path
   301→    )
   302→    SELECT
   303→      COUNT(*) as total_projects,
   304→      countIf(users = 1 AND sessions >= 5) as projects_with_silos,
   305→      round(AVG(users), 2) as avg_users_per_project,
   306→      argMax(project_path, sessions) as most_active_project,
   307→      max(sessions) as most_active_sessions
   308→    FROM project_stats
   309→  `;
   310→
   311→	const result = await queryClickhouse<ProjectSummary>(query);
   312→	return (
   313→		result[0] || {
   314→			total_projects: 0,
   315→			projects_with_silos: 0,
   316→			avg_users_per_project: 0,
   317→			most_active_project: "",
   318→			most_active_sessions: 0,
   319→		}
   320→	);
   321→}
   322→
   323→/**
   324→ * Get detailed metrics for a specific project
   325→ */
   326→export async function getProjectDetails(
   327→	orgId: string,
   328→	projectPath: string,
   329→	days = 30,
   330→): Promise<ProjectDetails | null> {
   331→	const org = escapeString(orgId);
   332→	const pp = escapeString(projectPath);
   333→	const d = Number(days);
   334→	const projectDisplaySubquery = buildProjectDisplaySubquery(org, pp);
   335→
   336→	const query = `
   337→    SELECT
   338→      any(project_path) as project_path,
   339→      COUNT(*) as total_sessions,
   340→      SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
   341→      SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
   342→      SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
   343→      COUNT(DISTINCT user_id) as contributors_count,
   344→      countIf(success_score < 40) as errors_count,
   345→      ifNull(round(avgOrNull(actual_duration_min), 2), 0) as avg_session_duration_min,
   346→      ifNull(round(avgOrNull(success_score), 2), 0) as success_rate,
   347→      round(SUM(actual_duration_min), 2) as total_duration_min
   348→    FROM rudel.session_analytics
   349→    WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   350→      AND ${buildDateFilter(d)}
   351→      AND organization_id = '${org}'
   352→      AND (git_remote != '' OR package_name != '' OR project_path != '')
   353→  `;
   354→
   355→	const results = await queryClickhouse<
   356→		ProjectDetails & {
   357→			input_tokens_sum: number;
   358→			output_tokens_sum: number;
   359→		}
   360→	>(query);
   361→
   362→	const [row] = results;
   363→	if (!row || row.total_sessions === 0) return null;
   364→	const cost =
   365→		row.output_tokens_sum * 0.000015 + row.input_tokens_sum * 0.000003;
   366→	return {
   367→		project_path: row.project_path,
   368→		total_sessions: row.total_sessions,
   369→		total_tokens: row.total_tokens,
   370→		contributors_count: row.contributors_count,
   371→		errors_count: row.errors_count,
   372→		avg_session_duration_min: row.avg_session_duration_min,
   373→		success_rate: row.success_rate,
   374→		total_duration_min: row.total_duration_min,
   375→		cost: parseFloat(cost.toFixed(4)),
   376→	};
   377→}
   378→
   379→/**
   380→ * Get contributors to a specific project
   381→ */
   382→export async function getProjectContributors(
   383→	orgId: string,
   384→	projectPath: string,
   385→	days = 30,
   386→): Promise<ProjectContributor[]> {
   387→	const org = escapeString(orgId);
   388→	const pp = escapeString(projectPath);
   389→	const d = Number(days);
   390→	const projectDisplaySubquery = buildProjectDisplaySubquery(org, pp);
   391→
   392→	const query = `
   393→    WITH project_totals AS (
   394→      SELECT COUNT(*) as total_sessions
   395→      FROM rudel.session_analytics
   396→      WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   397→        AND ${buildDateFilter(d)}
   398→        AND organization_id = '${org}'
   399→        AND (git_remote != '' OR package_name != '' OR project_path != '')
   400→    )
   401→    SELECT
   402→      user_id,
   403→      COUNT(*) as sessions,
   404→      round(SUM(actual_duration_min), 2) as total_duration_min,
   405→      SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
   406→      toString(min(session_date)) as first_session,
   407→      toString(max(session_date)) as last_session,
   408→      round(COUNT(*) * 100.0 / (SELECT total_sessions FROM project_totals), 2) as contribution_percentage
   409→    FROM rudel.session_analytics
   410→    WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   411→      AND ${buildDateFilter(d)}
   412→      AND organization_id = '${org}'
   413→      AND (git_remote != '' OR package_name != '' OR project_path != '')
   414→    GROUP BY user_id
   415→    ORDER BY sessions DESC
   416→  `;
   417→
   418→	return queryClickhouse<ProjectContributor>(query);
   419→}
