   421→/**
   422→ * Get feature usage for a specific project
   423→ */
   424→export async function getProjectFeatureUsage(
   425→	orgId: string,
   426→	projectPath: string,
   427→	days = 30,
   428→): Promise<ProjectFeatureUsage> {
   429→	const org = escapeString(orgId);
   430→	const pp = escapeString(projectPath);
   431→	const d = Number(days);
   432→	const projectDisplaySubquery = buildProjectDisplaySubquery(org, pp);
   433→
   434→	const adoptionQuery = `
   435→    SELECT
   436→      COUNT(*) as total_sessions,
   437→      countIf(length(subagent_types) > 0) as subagents_sessions,
   438→      countIf(length(skills) > 0) as skills_sessions,
   439→      countIf(length(slash_commands) > 0) as slash_commands_sessions
   440→    FROM rudel.session_analytics
   441→    WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   442→      AND ${buildDateFilter(d)}
   443→      AND organization_id = '${org}'
   444→      AND (git_remote != '' OR package_name != '' OR project_path != '')
   445→  `;
   446→
   447→	const topSubagentsQuery = `
   448→    SELECT val as name, count() as count
   449→    FROM rudel.session_analytics
   450→    ARRAY JOIN subagent_types as val
   451→    WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   452→      AND ${buildDateFilter(d)}
   453→      AND organization_id = '${org}'
   454→      AND (git_remote != '' OR package_name != '' OR project_path != '')
   455→      AND val != ''
   456→    GROUP BY val
   457→    ORDER BY count DESC
   458→    LIMIT 10
   459→  `;
   460→
   461→	const topSkillsQuery = `
   462→    SELECT val as name, count() as count
   463→    FROM rudel.session_analytics
   464→    ARRAY JOIN skills as val
   465→    WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   466→      AND ${buildDateFilter(d)}
   467→      AND organization_id = '${org}'
   468→      AND (git_remote != '' OR package_name != '' OR project_path != '')
   469→      AND val != ''
   470→    GROUP BY val
   471→    ORDER BY count DESC
   472→    LIMIT 10
   473→  `;
   474→
   475→	const topSlashCommandsQuery = `
   476→    SELECT val as name, count() as count
   477→    FROM rudel.session_analytics
   478→    ARRAY JOIN slash_commands as val
   479→    WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   480→      AND ${buildDateFilter(d)}
   481→      AND organization_id = '${org}'
   482→      AND (git_remote != '' OR package_name != '' OR project_path != '')
   483→      AND val != ''
   484→    GROUP BY val
   485→    ORDER BY count DESC
   486→    LIMIT 10
   487→  `;
   488→
   489→	const [adoptionResults, topSubagents, topSkills, topSlashCommands] =
   490→		await Promise.all([
   491→			queryClickhouse<{
   492→				total_sessions: number;
   493→				subagents_sessions: number;
   494→				skills_sessions: number;
   495→				slash_commands_sessions: number;
   496→			}>(adoptionQuery),
   497→			queryClickhouse<{ name: string; count: number }>(topSubagentsQuery),
   498→			queryClickhouse<{ name: string; count: number }>(topSkillsQuery),
   499→			queryClickhouse<{ name: string; count: number }>(topSlashCommandsQuery),
   500→		]);
   501→
   502→	if (adoptionResults.length === 0) {
   503→		return {
   504→			subagents_adoption_rate: 0,
   505→			skills_adoption_rate: 0,
   506→			slash_commands_adoption_rate: 0,
   507→			top_subagents: [],
   508→			top_skills: [],
   509→			top_slash_commands: [],
   510→		};
   511→	}
   512→
   513→	const [stats] = adoptionResults;
   514→	if (!stats)
   515→		return {
   516→			subagents_adoption_rate: 0,
   517→			skills_adoption_rate: 0,
   518→			slash_commands_adoption_rate: 0,
   519→			top_subagents: [],
   520→			top_skills: [],
   521→			top_slash_commands: [],
   522→		};
   523→	return {
   524→		subagents_adoption_rate:
   525→			stats.total_sessions > 0
   526→				? (stats.subagents_sessions / stats.total_sessions) * 100
   527→				: 0,
   528→		skills_adoption_rate:
   529→			stats.total_sessions > 0
   530→				? (stats.skills_sessions / stats.total_sessions) * 100
   531→				: 0,
   532→		slash_commands_adoption_rate:
   533→			stats.total_sessions > 0
   534→				? (stats.slash_commands_sessions / stats.total_sessions) * 100
   535→				: 0,
   536→		top_subagents: topSubagents,
   537→		top_skills: topSkills,
