   594→/**
   595→ * Get project trend data for time series charts (split by project)
   596→ */
   597→export async function getProjectTrends(
   598→	orgId: string,
   599→	days = 30,
   600→	groupBy: "day" | "week" = "day",
   601→): Promise<ProjectTrendDataPoint[]> {
   602→	const org = escapeString(orgId);
   603→	const d = Number(days);
   604→
   605→	const dateFunc =
   606→		groupBy === "week"
   607→			? "toMonday(toDate(session_date))"
   608→			: "toDate(session_date)";
   609→
   610→	const query = `
   611→    SELECT
   612→      toString(${dateFunc}) as date,
   613→      ${PROJECT_DISPLAY_EXPR} as project_key,
   614→      any(project_path) as _project_path,
   615→      COUNT(*) as sessions,
   616→      round(SUM(actual_duration_min) / 60, 2) as total_hours,
   617→      SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
   618→      round(AVG(success_score), 2) as avg_success_rate
   619→    FROM rudel.session_analytics
   620→    WHERE ${buildDateFilter(d)}
   621→      AND organization_id = '${org}'
   622→      AND (git_remote != '' OR package_name != '' OR project_path != '')
   623→    GROUP BY date, ${PROJECT_DISPLAY_EXPR}
   624→    ORDER BY date ASC, project_key ASC
   625→  `;
   626→
   627→	const results = await queryClickhouse<
   628→		ProjectTrendDataPoint & { project_key: string; _project_path: string }
   629→	>(query);
   630→
   631→	return results.map((item) => ({
   632→		date: item.date,
   633→		project_path: item._project_path,
   634→		project_name: item.project_key,
   635→		sessions: item.sessions,
   636→		total_hours: item.total_hours,
   637→		total_tokens: item.total_tokens,
   638→		avg_success_rate: item.avg_success_rate,
   639→	}));
   640→}
