    46→// ── Inline test server helper (avoids cross-package TS rootDir issue) ──
    47→
    48→const MONOREPO_ROOT = resolve(import.meta.dir, "..", "..", "..", "..");
    49→
    50→interface TestServer {
    51→	port: number;
    52→	baseUrl: string;
    53→	stop: () => Promise<void>;
    54→	ensureAlive: () => Promise<void>;
    55→}
    56→
    57→function spawnServer(env: Record<string, string | undefined>) {
    58→	const proc = Bun.spawn(["bun", "apps/api/src/index.ts"], {
    59→		cwd: MONOREPO_ROOT,
    60→		stdout: "pipe",
    61→		stderr: "pipe",
    62→		env,
    63→	});
    64→	proc.unref();
    65→	return proc;
    66→}
    67→
    68→function drainStreams(proc: ReturnType<typeof Bun.spawn>) {
    69→	if (proc.stdout instanceof ReadableStream)
    70→		proc.stdout.pipeTo(new WritableStream()).catch(() => {});
    71→	if (proc.stderr instanceof ReadableStream)
    72→		proc.stderr.pipeTo(new WritableStream()).catch(() => {});
    73→}
    74→
    75→async function parseReadyPort(
    76→	proc: ReturnType<typeof Bun.spawn>,
    77→): Promise<number> {
    78→	const stdout = proc.stdout;
    79→	if (!stdout || !(stdout instanceof ReadableStream))
    80→		throw new Error("Server process has no readable stdout");
    81→	const reader = stdout.getReader();
    82→	const decoder = new TextDecoder();
    83→	let buffer = "";
    84→	const deadline = Date.now() + 30_000;
    85→	try {
    86→		while (Date.now() < deadline) {
    87→			const { value, done } = await reader.read();
    88→			if (done) break;
    89→			buffer += decoder.decode(value, { stream: true });
    90→			const match = buffer.match(/listening on https?:\/\/localhost:(\d+)/i);
    91→			if (match?.[1]) {
    92→				reader.releaseLock();
    93→				return Number.parseInt(match[1], 10);
    94→			}
    95→		}
    96→	} catch {
    97→		// fall through
    98→	}
    99→	proc.kill();
   100→	throw new Error(`Server did not become ready within 30s`);
   101→}
   102→
   103→async function waitForReady(baseUrl: string): Promise<void> {
   104→	const deadline = Date.now() + 10_000;
   105→	while (Date.now() < deadline) {
   106→		try {
   107→			const res = await fetch(`${baseUrl}/health`, {
   108→				signal: AbortSignal.timeout(2000),
   109→			});
   110→			if (res.ok) return;
   111→		} catch {
   112→			// retry
   113→		}
   114→		await Bun.sleep(200);
   115→	}
   116→	throw new Error(`Server at ${baseUrl} did not respond within 10s`);
   117→}
   118→
   119→async function startTestServer(): Promise<TestServer> {
   120→	const env = {
   121→		...process.env,
   122→		PORT: "0",
   123→		APP_URL: "http://localhost",
   124→		BETTER_AUTH_SECRET: "test-secret-for-integration-tests",
   125→		ALLOWED_ORIGIN: "http://localhost",
   126→	};
   127→	let proc = spawnServer(env);
   128→	let port = await parseReadyPort(proc);
   129→	drainStreams(proc);
   130→	await waitForReady(`http://localhost:${port}`);
   131→
   132→	return {
   133→		get port() {
   134→			return port;
   135→		},
   136→		get baseUrl() {
   137→			return `http://localhost:${port}`;
   138→		},
   139→		async stop() {
   140→			proc.kill();
   141→			await proc.exited;
   142→		},
   143→		async ensureAlive() {
   144→			try {
   145→				const res = await fetch(`http://localhost:${port}/health`, {
   146→					signal: AbortSignal.timeout(2000),
   147→				});
   148→				if (res.ok) return;
   149→			} catch {
   150→				// restart
   151→			}
   152→			proc = spawnServer(env);
   153→			port = await parseReadyPort(proc);
   154→			drainStreams(proc);
   155→			await waitForReady(`http://localhost:${port}`);
   156→		},
   157→	};
   158→}
