   162→function parseArray<T>(
   163→	schema: { parse: (v: unknown) => T },
   164→	data: unknown,
   165→): T[] {
   166→	if (!Array.isArray(data))
   167→		throw new Error(`Expected array, got ${typeof data}`);
   168→	return data.map((item: unknown) => schema.parse(item));
   169→}
