   186→// ── RPC helper ──────────────────────────────────────────────────────
   187→
   188→async function rpc(
   189→	path: string,
   190→	input?: Record<string, unknown>,
   191→): Promise<unknown> {
   192→	const res = await fetch(`${server.baseUrl}/rpc/${path}`, {
   193→		method: "POST",
   194→		headers: {
   195→			"Content-Type": "application/json",
   196→			Authorization: `Bearer ${token}`,
   197→		},
   198→		body: JSON.stringify(input ? { json: input } : {}),
   199→	});
   200→	const data = await res.json();
   201→	if (!res.ok)
   202→		throw new Error(`RPC ${path}: ${res.status} ${JSON.stringify(data)}`);
   203→	return (data as { json: unknown }).json;
   204→}
