```typescript
export async function getProjectDetails(
	orgId: string,
	projectPath: string,
	days = 30,
): Promise<ProjectDetails | null> {
	const org = escapeString(orgId);
	const pp = escapeString(projectPath);
	const d = Number(days);
	const projectDisplaySubquery = buildProjectDisplaySubquery(org, pp);

	const query = `
    SELECT
      any(project_path) as project_path,
      COUNT(*) as total_sessions,
      SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
      SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
      SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
      COUNT(DISTINCT user_id) as contributors_count,
      countIf(success_score < 40) as errors_count,
      ifNull(round(avgOrNull(actual_duration_min), 2), 0) as avg_session_duration_min,
      ifNull(round(avgOrNull(success_score), 2), 0) as success_rate,
      round(SUM(actual_duration_min), 2) as total_duration_min
    FROM rudel.session_analytics
    WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
      AND ${buildDateFilter(d)}
      AND organization_id = '${org}'
      AND (git_remote != '' OR package_name != '' OR project_path != '')
  `;

	const results = await queryClickhouse<
		ProjectDetails & {
			input_tokens_sum: number;
			output_tokens_sum: number;
		}
	>(query);

	const [row] = results;
	if (!row || row.total_sessions === 0) return null;
	const cost =
		row.output_tokens_sum * 0.000015 + row.input_tokens_sum * 0.000003;
	return {
		project_path: row.project_path,
		total_sessions: row.total_sessions,
		total_tokens: row.total_tokens,
		contributors_count: row.contributors_count,
		errors_count: row.errors_count,
		avg_session_duration_min: row.avg_session_duration_min,
		success_rate: row.success_rate,
		total_duration_min: row.total_duration_min,
		cost: parseFloat(cost.toFixed(4)),
	};
}
```

### Key Implementation Details

**Project Matching Logic** (lines 15-38 of project.service.ts):

The endpoint uses a sophisticated `PROJECT_KEY_EXPR` to match projects flexibly:
- Prefers `git_remote` if available
- Falls back to `package_name`
- Falls back to `project_path`

```typescript
const PROJECT_KEY_EXPR = `if(git_remote != '', git_remote, if(package_name != '', package_name, project_path))`;
```

A subquery (`buildProjectDisplaySubquery`) finds the project and determines its display name using the same logic.

**Metrics Calculated**:
- `total_sessions`: Total session count
- `total_tokens`: Sum of input + output tokens
- `contributors_count`: Distinct user count
- `errors_count`: Sessions with success_score < 40
- `avg_session_duration_min`: Average session duration (in minutes)
- `success_rate`: Average success score
- `total_duration_min`: Sum of all session durations
- `cost`: Calculated from token usage (output tokens × $0.000015 + input tokens × $0.000003)

