import type {
	ProjectContributor as ProjectContributorBase,
	ProjectDetailData,
	ProjectError as ProjectErrorBase,
	ProjectFeatureUsage,
	ProjectInvestment,
	ProjectTrendDataPoint as ProjectTrendDataPointBase,
} from "@rudel/api-routes";
import {
	buildDateFilter,
	escapeString,
	queryClickhouse,
} from "../clickhouse.js";

const PROJECT_KEY_EXPR = `if(git_remote != '', git_remote, if(package_name != '', package_name, project_path))`;
const PROJECT_DISPLAY_EXPR = `if(git_remote != '', arrayElement(splitByChar('/', git_remote), -1), arrayElement(splitByChar('/', project_path), -1))`;

function buildProjectDisplaySubquery(
	org: string,
	escapedProjectPath: string,
): string {
	return `(
    SELECT
      if(
        count() > 0,
        any(${PROJECT_DISPLAY_EXPR}),
        if(position('${escapedProjectPath}', '/') > 0, arrayElement(splitByChar('/', '${escapedProjectPath}'), -1), '${escapedProjectPath}')
      ) as project_display
    FROM rudel.session_analytics
    WHERE organization_id = '${org}'
      AND (
        project_path = '${escapedProjectPath}'
        OR git_remote = '${escapedProjectPath}'
        OR ${PROJECT_KEY_EXPR} = '${escapedProjectPath}'
      )
      AND (git_remote != '' OR package_name != '' OR project_path != '')
  )`;
}

export interface KnowledgeSilo {
	project_path: string;
	project_name?: string;
	repository_name?: string;
	sole_user: string;
	sessions: number;
	risk_level: "high" | "medium" | "low";
}

export interface ProjectActivity {
	date: string;
	project_path: string;
	sessions: number;
	unique_users: number;
}

export interface ProjectSummary {
	total_projects: number;
	projects_with_silos: number;
	avg_users_per_project: number;
	most_active_project: string;
	most_active_sessions: number;
}

export type ProjectDetails = ProjectDetailData;

export interface ProjectContributor extends ProjectContributorBase {
	username?: string;
	first_session: string;
	last_session: string;
}

export interface ProjectError extends ProjectErrorBase {
	first_seen: string;
}

export interface ProjectTrendDataPoint extends ProjectTrendDataPointBase {
	project_name?: string;
}

