    18→const PROJECT_KEY_EXPR = `if(git_remote != '', git_remote, if(package_name != '', package_name, project_path))`;
    19→const PROJECT_DISPLAY_EXPR = `if(git_remote != '', arrayElement(splitByChar('/', git_remote), -1), arrayElement(splitByChar('/', project_path), -1))`;
    20→
    21→function buildProjectDisplaySubquery(
    22→	org: string,
    23→	escapedProjectPath: string,
    24→): string {
    25→	return `(
    26→    SELECT
    27→      if(
    28→        count() > 0,
    29→        any(${PROJECT_DISPLAY_EXPR}),
    30→        if(position('${escapedProjectPath}', '/') > 0, arrayElement(splitByChar('/', '${escapedProjectPath}'), -1), '${escapedProjectPath}')
    31→      ) as project_display
    32→    FROM rudel.session_analytics
    33→    WHERE organization_id = '${org}'
    34→      AND (
    35→        project_path = '${escapedProjectPath}'
    36→        OR git_remote = '${escapedProjectPath}'
    37→        OR ${PROJECT_KEY_EXPR} = '${escapedProjectPath}'
    38→      )
    39→      AND (git_remote != '' OR package_name != '' OR project_path != '')
    40→  )`;
    41→}
