   238→/**
   239→ * Get project activity trend over time
   240→ */
   241→export async function getProjectActivity(
   242→	orgId: string,
   243→	projectPath: string,
   244→	params: { days?: number; granularity?: "day" | "week" | "month" } = {},
   245→): Promise<ProjectActivity[]> {
   246→	const { days = 30, granularity = "day" } = params;
   247→	const org = escapeString(orgId);
   248→	const pp = escapeString(projectPath);
   249→	const d = Number(days);
   250→
   251→	let dateGrouping = "toDate(session_date)";
   252→	if (granularity === "week") {
   253→		dateGrouping = "toMonday(session_date)";
   254→	} else if (granularity === "month") {
   255→		dateGrouping = "toStartOfMonth(session_date)";
   256→	}
   257→
   258→	const query = `
   259→    WITH project_key AS (
   260→      SELECT if(git_remote != '', git_remote, if(package_name != '', package_name, project_path)) as pk, any(project_path) as project_path
   261→      FROM rudel.session_analytics
   262→      WHERE project_path = '${pp}'
   263→        AND (git_remote != '' OR package_name != '' OR project_path != '')
   264→        AND organization_id = '${org}'
   265→      LIMIT 1
   266→    )
   267→    SELECT
   268→      toString(${dateGrouping}) as date,
   269→      pk.project_path,
   270→      COUNT(*) as sessions,
   271→      COUNT(DISTINCT s.user_id) as unique_users
   272→    FROM project_key pk
   273→    INNER JOIN rudel.session_analytics s ON if(s.git_remote != '', s.git_remote, if(s.package_name != '', s.package_name, s.project_path)) = pk.pk
   274→    WHERE s.${buildDateFilter(d)}
   275→      AND s.organization_id = '${org}'
   276→    GROUP BY ${dateGrouping}, pk.project_path
   277→    ORDER BY date ASC
   278→  `;
   279→
   280→	return queryClickhouse<ProjectActivity>(query);
   281→}
