   326→/**
   327→ * Get detailed metrics for a specific project
   328→ */
   329→export async function getProjectDetails(
   330→	orgId: string,
   331→	projectPath: string,
   332→	days = 30,
   333→): Promise<ProjectDetails | null> {
   334→	const org = escapeString(orgId);
   335→	const pp = escapeString(projectPath);
   336→	const d = Number(days);
   337→	const projectDisplaySubquery = buildProjectDisplaySubquery(org, pp);
   338→
   339→	const query = `
   340→    SELECT
   341→      any(project_path) as project_path,
   342→      COUNT(*) as total_sessions,
   343→      SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
   344→      SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
   345→      SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
   346→      COUNT(DISTINCT user_id) as contributors_count,
   347→      countIf(success_score < 40) as errors_count,
   348→      ifNull(round(avgOrNull(actual_duration_min), 2), 0) as avg_session_duration_min,
   349→      ifNull(round(avgOrNull(success_score), 2), 0) as success_rate,
   350→      round(SUM(actual_duration_min), 2) as total_duration_min
   351→    FROM rudel.session_analytics
   352→    WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   353→      AND ${buildDateFilter(d)}
   354→      AND organization_id = '${org}'
   355→      AND (git_remote != '' OR package_name != '' OR project_path != '')
   356→  `;
   357→
   358→	let results: (ProjectDetails & {
   359→		input_tokens_sum: number;
   360→		output_tokens_sum: number;
   361→	})[];
   362→	try {
   363→		results = await queryClickhouse<
   364→			ProjectDetails & {
   365→				input_tokens_sum: number;
   366→				output_tokens_sum: number;
   367→			}
   368→		>(query);
   369→	} catch (err) {
   370→		logger.error(
   371→			"getProjectDetails ClickHouse query failed for org={org} path={path}: {error}",
   372→			{ org: orgId, path: projectPath, error: String(err) },
   373→		);
   374→		throw err;
