   570→	const query = `
   571→    WITH error_extracts AS (
   572→      SELECT
   573→        session_id,
   574→        user_id,
   575→        session_date,
   576→        CASE
   577→          WHEN content LIKE '%OperationFailed%' THEN 'OperationFailed'
   578→          WHEN content LIKE '%UnknownError%' THEN 'UnknownError'
   579→          WHEN content LIKE '%ORPCError%' THEN 'ORPCError'
   580→          WHEN content LIKE '%TimeoutError%' THEN 'TimeoutError'
   581→          WHEN content LIKE '%TypeError%' THEN 'TypeError'
   582→          WHEN content LIKE '%ReferenceError%' THEN 'ReferenceError'
   583→          WHEN content LIKE '%Error:%' OR content LIKE '%error:%' THEN 'GenericError'
   584→          ELSE NULL
   585→        END as error_pattern
   586→      FROM rudel.session_analytics
   587→      WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   588→        AND ${buildDateFilter(d)}
   589→        AND organization_id = '${org}'
   590→        AND (git_remote != '' OR package_name != '' OR project_path != '')
