   595→      COUNT(*) as occurrences,
   596→      uniq(user_id) as affected_users,
   597→      toString(min(session_date)) as first_seen,
   598→      toString(max(session_date)) as last_seen
   599→    FROM error_extracts
   600→    WHERE error_pattern IS NOT NULL
   601→    GROUP BY error_pattern
   602→    ORDER BY occurrences DESC
   603→    LIMIT 20
   604→  `;
   605→
   606→	return queryClickhouse<ProjectError>(query);
